mapper.select:
select c.*, m.major_name as majorName, co.id as collegeId, co.college_name as collegeName from clazz c
left join major m on c.major_id = m.id
left join college co on m.college_id = co.id


        and c.clazz_name like concat('%',#{clazzName},'%')


        and c.grade = #{grade}


        and c.major_id = #{majorId}


        and co.id = #{collegeId}
